adjudicated_actions.old_string:
await page.locator('select').nth(1).selectOption('审批中');
await expect(page.getByText('资产转移审批').first()).toBeVisible();
// 默认全部显示，已批准审批仍然在列表中

adjudicated_actions.new_string:
// 新版使用 Tab 按钮过滤状态（兼容 tab/button role）
await page.locator('[role="tab"], [role="button"]').getByText('待审批', { exact: true }).first().click();
await expect(page.getByText('资产转移审批').first()).toBeVisible();
// 默认全部显示，已批准审批仍然在列表中

adjudicated_actions.old_string:
await page.goto('/approvals');
await page.getByRole('button', { name: '驳回' }).first().click();
// 确认驳回对话框
await page.getByPlaceholder('请输入驳回原因...').fill('测试驳回');
await page.getByRole('button', { name: '确认驳回' }).click();
await expect(page.getByText('已驳回').first()).toBeVisible();

adjudicated_actions.new_string:
await page.goto('/approval');
// 新版审批操作：先点击列表项打开详情弹窗，再在 ApprovalActionPanel 中操作
await page.getByText('资产转移审批').first().click();
await expect(page.getByRole('dialog')).toBeVisible({ timeout: 5000 });
await page.getByRole('textbox').fill('测试驳回');
await page.getByRole('button', { name: '驳回' }).click();
await expect(page.getByText('已驳回').first()).toBeVisible();
